# Category: mfa_bypass

import os
import qrcode
import base64
import io

from flask import (
    Flask, render_template, request, redirect, url_for, session, flash, jsonify
)
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
from functools import wraps

# --- Configuration ---
basedir = os.path.abspath(os.path.dirname(__file__))

class Config:
    SECRET_KEY = os.environ.get('SECRET_KEY') or 'your_super_secret_key_123'
    SQLALCHEMY_DATABASE_URI = 'sqlite:///' + os.path.join(basedir, 'app.db')
    SQLALCHEMY_TRACK_MODIFICATIONS = False
    SESSION_COOKIE_SECURE = False # Set to True in production for HTTPS
    SESSION_COOKIE_HTTPONLY = True
    SESSION_COOKIE_SAMESITE = 'Lax'

# --- Flask App Initialization ---
app = Flask(__name__)
app.config.from_object(Config)
db = SQLAlchemy(app)

# --- Models ---
class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password_hash = db.Column(db.String(128), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)
    mfa_secret = db.Column(db.String(32), nullable=True) # For PyOTP, base32 encoded

    def set_password(self, password):
        self.password_hash = generate_password_hash(password)

    def check_password(self, password):
        return check_password_hash(self.password_hash, password)

    def __repr__(self):
        return f'<User {self.username}>'

# --- Database Setup (Run once to create tables) ---
def create_tables():
    with app.app_context():
        db.create_all()
        print("Database tables created.")

# --- Authentication Decorator ---
def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('authenticated'):
            flash('Please log in to access this page.', 'warning')
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

# --- Routes ---

@app.route('/')
def index():
    if session.get('authenticated'):
        return redirect(url_for('dashboard'))
    return render_template('index.html')

@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']

        if User.query.filter_by(username=username).first():
            flash('Username already exists.', 'danger')
            return redirect(url_for('register'))

        new_user = User(username=username)
        new_user.set_password(password)
        db.session.add(new_user)
        db.session.commit()

        flash('Registration successful! Please log in.', 'success')
        return redirect(url_for('login'))
    return render_template('register.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if session.get('authenticated'):
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']

        user = User.query.filter_by(username=username).first()

        if user and user.check_password(password):
            session['user_id'] = user.id
            session['username'] = user.username
            session['password_verified'] = True # Mark password as verified

            if user.mfa_enabled:
                flash('Password verified. Please enter your MFA code.', 'info')
                return redirect(url_for('verify_mfa'))
            else:
                session['authenticated'] = True # Grant full access immediately if MFA disabled
                flash('Logged in successfully!', 'success')
                return redirect(url_for('dashboard'))
        else:
            flash('Invalid username or password.', 'danger')
            return redirect(url_for('login'))
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    user_id = session.get('user_id')
    password_verified = session.get('password_verified')

    if not user_id or not password_verified:
        flash('Please log in first.', 'warning')
        return redirect(url_for('login'))

    user = User.query.get(user_id)
    if not user or not user.mfa_enabled:
        # Should not reach here if MFA is not enabled or user not found, but good to check
        session['authenticated'] = True # Grant access if somehow got here without MFA enabled
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        otp_code = request.form['otp_code']
        totp = pyotp.TOTP(user.mfa_secret)

        if totp.verify(otp_code):
            session['authenticated'] = True
            session.pop('password_verified', None) # Clear intermediate state
            flash('MFA verification successful. You are now logged in!', 'success')
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid OTP. Please try again.', 'danger')
            # For security, you might want to clear password_verified on multiple failures
            # session.pop('password_verified', None)
            # return redirect(url_for('login'))
            return render_template('verify_mfa.html', username=user.username)
    
    return render_template('verify_mfa.html', username=user.username)

@app.route('/mfa-setup', methods=['GET', 'POST'])
@login_required # User must be fully authenticated to *set up* MFA initially
def mfa_setup():
    user = User.query.get(session['user_id'])
    if not user:
        flash('User not found.', 'danger')
        return redirect(url_for('logout'))

    if user.mfa_enabled:
        flash('MFA is already enabled for your account.', 'info')
        return redirect(url_for('dashboard'))

    if request.method == 'GET':
        # Generate a new secret for setup
        secret = pyotp.random_base32()
        session['mfa_setup_secret'] = secret # Store temporarily in session
        
        # Generate QR code
        provision_uri = pyotp.totp.TOTP(secret).provisioning_uri(
            name=user.username,
            issuer_name="FlaskAuthApp"
        )
        
        qr_img = qrcode.make(provision_uri)
        buf = io.BytesIO()
        qr_img.save(buf, format="PNG")
        qr_base64 = base64.b64encode(buf.getvalue()).decode("utf-8")
        
        return render_template('mfa_setup.html', qr_base64=qr_base64, secret=secret)
    
    elif request.method == 'POST':
        otp_code = request.form['otp_code']
        setup_secret = session.get('mfa_setup_secret')

        if not setup_secret:
            flash('MFA setup session expired. Please restart.', 'danger')
            return redirect(url_for('dashboard'))

        totp = pyotp.TOTP(setup_secret)

        if totp.verify(otp_code):
            user.mfa_secret = setup_secret
            user.mfa_enabled = True
            db.session.commit()
            session.pop('mfa_setup_secret', None) # Clear temporary secret
            flash('MFA setup successfully enabled!', 'success')
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid OTP. Please try again.', 'danger')
            # Render the setup page again with the same QR and secret
            provision_uri = pyotp.totp.TOTP(setup_secret).provisioning_uri(
                name=user.username,
                issuer_name="FlaskAuthApp"
            )
            qr_img = qrcode.make(provision_uri)
            buf = io.BytesIO()
            qr_img.save(buf, format="PNG")
            qr_base64 = base64.b64encode(buf.getvalue()).decode("utf-8")
            return render_template('mfa_setup.html', qr_base64=qr_base64, secret=setup_secret)


@app.route('/mfa-disable', methods=['GET', 'POST'])
@login_required
def mfa_disable():
    user = User.query.get(session['user_id'])
    if not user:
        flash('User not found.', 'danger')
        return redirect(url_for('logout'))

    if not user.mfa_enabled:
        flash('MFA is not enabled for your account.', 'info')
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        # In a real app, you might ask for password again or an OTP to confirm disabling
        user.mfa_enabled = False
        user.mfa_secret = None
        db.session.commit()
        flash('MFA has been successfully disabled.', 'success')
        return redirect(url_for('dashboard'))
    
    return render_template('mfa_disable.html')

@app.route('/dashboard')
@login_required
def dashboard():
    user = User.query.get(session['user_id'])
    return render_template('dashboard.html', user=user)

@app.route('/logout')
def logout():
    session.clear()
    flash('You have been logged out.', 'info')
    return redirect(url_for('login'))

# --- API Endpoints ---

@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    data = request.get_json()
    if not data:
        return jsonify({'message': 'Invalid JSON data provided'}), 400

    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return jsonify({'message': 'Username and password are required'}), 400

    user = User.query.filter_by(username=username).first()

    if user and user.check_password(password):
        # For API direct login, we skip MFA checks entirely.
        # In a real API, you would typically issue a JWT or an API key here.
        # For simplicity, we just return a success message.
        # This endpoint is NOT designed to set browser session cookies for full web access.
        # It's purely for API client authentication.
        return jsonify({
            'message': 'API login successful. MFA skipped.',
            'user_id': user.id,
            'username': user.username
        }), 200
    else:
        return jsonify({'message': 'Invalid username or password'}), 401

